void printArray(int arr[], int size) {
    for (int i = 0; i < size; i++) {
        printf("%d ", arr[i]);
    }
}

void doubleFirst(int arr[]) {
    arr[0] = arr[0] * 2;
}

int main() {
    int nums[3] = {5, 10, 15};
    doubleFirst(nums);
    printf("%d", nums[0]);
    return 0;
}

void tryToChange(int x) {
    x = 100;
}

int main() {
    int y = 5;
    tryToChange(y);
    printf("%d", y);
    return 0;
}

int sumArray(int arr[], int size) {
    int sum = 0;
    for (int i = 0; i < size; i++) {
        sum += arr[i];
    }
    return sum;
}

float averageArray(int arr[], int size) {
    return (float) sumArray(arr, size) / size;
}

int countAbove(int arr[], int size, int threshold) {
    int count = 0;
    for (int i = 0; i < size; i++) {
        if (arr[i] > threshold) count++;
    }
    return count;
}
